INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_914487','Пісня про обступлення татарами Києва...','(Темінь часу минуло...). Музика: Ярослав Юрчишин Слова: Ярослав Юрчишин. Виконує: Ярослав Юрчишин','uk','ukraine_1991',NULL,'2001','Співаник Лицаря.- Київ–Львів: Орден Залізної Остроги, 2004.- 110 с.','Повна назва пісні: "Пісня про обступлення татарами Києва року 1239 від Різдва Христового". "...Пісня створена за аналогією балад-речитативів княжої доби, які до нас в оригіналах, на жаль, не дійшли. Найкращим зразком пізніх речитативів можна назвати "Слово о полку Ігоревім...", яке дійшло до нас у переписі. До цієї форми зверталися українці всіх поколінь. Серед сучасних бардів цей тип пісень розвивають Василь Жданкін та Едуард Драч. Пісня написана після знайомства львівських та київських пластунів на спільних заходах у 2001 році - зустріч Папи Римського, Дні Пласту в Києві, Орликіаді." (Джерело: Співаник Лицаря.- Київ–Львів, 2004)','Темінь часу минуло   з тих буремних віків,
Як наш злотоверхий Київ   хан Батий обступив,
Татарва обсіла кручі старого Дніпра, -
Місто тоді боронили галицькі вої князя Данила.

Приспів:
Руська земле, славна во віки єси,
Твої діти зупинили   татарськії орди.

Хмари небо закривають,   темінь світ огорта.
Б''ються хоробро вої   тисяцького Дмитра.
Йому сам князь Данило місто велів берегти
І у бою з бусурманином   на смерть вистояти.

Б''ються вої хоробро і не день, і не два -
Вже на мурах іде бій. Напира татарва,
Хан гінців посилає до Дмитра в котрий раз:
"Дайте місто - вам чуже воно - ми помилуєм вас".

Приспів:
Руська земле, славна во віки єси,
Твої діти зупинили татарськії орди.

На спис воєвода сперся, Галич рідний згадав,
Той наділ, що йому князь та й за службу віддав,
Згадав жону молоду і синів-соколів -
І хановим посланцям він таке відповів:

"Вам нас не зрозуміти - у вас дому нема,
Нам що Галич, що Київ - Україна одна,
Ми присягу складали до смерті боронить,
То ж, поки живий хоча б один,
міста вам не полонить.

Скільки років минуло з тих буремних віків,
Як в останню атаку Дмитро воїв повів,
Трупом Київ встелили галицькі вояки,
Скарб соборної держави та й нам передали.

Приспів:
Руська земле, мати героїв-синів,
Чи нащадки зуміють бути гідними дідів?

Приспів:
Руська земле, славна во віки єси.
Твої діти зупинили татарськії орди.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_914487'), datetime('now')),datetime('now'));
