INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9142989','Отаман Сірко','Музика: Олександр Осадчий Слова: Олексій Кононенко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Там, де Січ - святая ненька,
Де Дніпро - ріка,
Закричали запорожці
Кошовим Сірка,
Обирали отаманом,
На чоло - землицю,
Щоби знав козацьку шану,
Щоб не став гордиться.

Приспів:
Кошовий атаман - своїй шабельці пан -
Отаман Сірко.
Своїй шабельці пан -вороженькам шайтан -
Отаман Сірко.
Не король і не хан, не турецький султан -
ОТАМАН Сірко.
Не шинкар і не дяк - запорізький козак-
ОТАМАН Сірко!

Я к збирались запорожці
Брати Перекоп,
Попереду кониченьком
Кошовий Сірко.
Вилітав орлом з долини
У широке поле
Буде слава Україні,
ЇЇ дітям воля.

Приспів.

Як нагонить бусурманів
Кровожерний кат,
Гайда, братці, на могилу
Славного Сірка,
Відкопайте шаблю гостру
З правою рукою,
Хай не знають вражі гості
Сім років покою.

Приспів.    Фонограма-мінус (mp3, 196 kbps)','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9142989'), datetime('now')),datetime('now'));
