INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_915181','Золото Карпат','Музика: Степан Гіга Слова: Василь Кузан. Виконує: Іван Попович','uk','ukraine_1991',NULL,NULL,'1. Авторське подання','Виконує Іван Попович','У полоні міст, мерехтінні літ
У душі вогонь, за плечима світ,
Де гладкий асфальт, мов карпатський бук,
І летить печаль, мов трембіти звук.

Приспів:
Золото Карпат, золото пісень,
Я несу до вас у святковий день.
Хай вони дзвенять, хай лунають і
Щастя і любов будуть на землі.

Крізь столичний шум чую, як ручай
Кличе до батьків, просить: зустрічай!
Це тепло землі, цю любов Карпат,
Де серед краси - кожен друг і брат.

Приспів.

Кожен друг і брат, мати і сестра.
Щастя і любов нам несе краса:
Чарівний ручай і карпатський бук,
Світ із полонин і трембіти звук.

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_915181'), datetime('now')),datetime('now'));
