INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9140585','Лебеденко','Українська народна пісня. Виконує: Сонцекльош','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, як поїхав да пан Лебеденко
До млина за мукою,
Гей, зустрічають його гайдамаки
В темнім лузі над рікою:
Ой, здоров, здоров був, пане Лебеденку,
Як ми тебе довго ждали.
Через тебе, пане, пане Лебеденку,
Ми три нічки та й не спали.

Через тебе, пане, пане Лебеденку,
Ми три нічки не спали,
А все тебе, пане, пане Лебеденку,
А все тебе ожидали.
Ох, випряж, випряж, пане Лебеденку,
Свого коня вороного.
Не випряжу, вражі, вражі гайдамаки,
А хоч вас тут і много.

Ох, і випряж, випряж, пане Лебеденку,
Хоч і пристяжну кобилу.
Не випряжу, вражі, вражі гайдамаки,
А хоч сам тут і загину.
Ой, і взяли пана, пана Лебеденка
Да й на три штики вгору,
Да й вдарили пана, пана Лебеденка
Об сухий пень головою.
Оце ж тобі, пане, пане Лебеденку,
На твою гарную вроду.
Ой, щоб не топити та нас, гайдамаків,
У холодную воду!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9140585'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9140585','Лебеденко','Ой, як поїхав да пан Лебеденко
До млина за мукою,
Гей, зустрічають його гайдамаки
В темнім лузі над рікою:
Ой, здоров, здоров був, пане Лебеденку,
Як ми тебе довго ждали.
Через тебе, пане, пане Лебеденку,
Ми три нічки та й не спали.

Через тебе, пане, пане Лебеденку,
Ми три нічки не спали,
А все тебе, пане, пане Лебеденку,
А все тебе ожидали.
Ох, випряж, випряж, пане Лебеденку,
Свого коня вороного.
Не випряжу, вражі, вражі гайдамаки,
А хоч вас тут і много.

Ох, і випряж, випряж, пане Лебеденку,
Хоч і пристяжну кобилу.
Не випряжу, вражі, вражі гайдамаки,
А хоч сам тут і загину.
Ой, і взяли пана, пана Лебеденка
Да й на три штики вгору,
Да й вдарили пана, пана Лебеденка
Об сухий пень головою.
Оце ж тобі, пане, пане Лебеденку,
На твою гарную вроду.
Ой, щоб не топити та нас, гайдамаків,
У холодную воду!');
