INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9147683','Скоро Новий Рік','Музика: Степан Вовкун Слова: Степан Вовкун. Виконує: Esteban','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сніжно біло - згадка про літо,
Крок за кроком лишаєм сліди,
День за днем все ближче і ближче
До нас в гості наближається свято.
З наступаючим! З наступаючим!

Приспів:
Я загадаю бажання,
Бо скоро Новий Рік!
Хай запалає в серцях кохання
На сотні тисяч літ!
Ти загадай і собі бажання,
Бо скоро Рік Новий!
Він принесе нам те, що побажаєм,
Те, що не приніс старий!

Морозний вітер, гарячі серця,
Холодні лавки, палкі поцілунки,
І хоч на дворі настала зима -
У серці в мене тепла пора!

Приспів. (4)','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9147683'), datetime('now')),datetime('now'));
