INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_913686','Заспіваймо пісню веселеньку','(Сусідко, сусідко). Слова: УСС. Виконує: Гайдамаки, Ансамбль Львівського Університету "Черемош", Рушничок','uk','ukr_ssr_1919_1991',NULL,'1954',NULL,'Цю пісню часто сприймають як українську народну. Насправді ж це стрілецький жартівливий переспів мадярської (угорської) народної пісні. "...Немалий слід залишив на стрілецьких піснях побут на Закарпатті. Там принялися деякі закарпатські й лемківські мелодії, там прослизнулися й деякі чисто мадярські, до яких підкладено український текст. Такі пісні, як "Гей, ви стрільці січовії" або "Ой, сусідко" – то були для стрільців тільки пісні-жарти. Проте згодом вони, особливо ж "Сусідка", розповсюдилися і – з шкодою – стали входити у програми концертів українських народних пісень..." (Витвицький Василь. Михайло Гайворонський. Життя і творчість. – Нью-Йорк, 1954; http://ozo.org.ua/spivanyk.php?sid=2). У виконанні гурту Рушничок: http://chomikuj.pl/WDR/Muzyka+Ukrai*c5*84ska/Narodowa+-+Folk+-+Regionalna/Rushnychok','Заспіваймо пісню веселеньку,
Про сусідку молоденьку,
Про сусідку заспіваймо,
Серце наше звеселяймо!

- Ой, сусідко, сусідко, сусідко,
C
Позич мені решітко, решітко:
Я си муки потрясу, потрясу,            |
Am                       |
Завтра вранці принесу, принесу.        | (2)

Заспіваймо пісню веселеньку,
Про венгерку молоденьку,
Про венгерку заспіваймо,
Серце наше звеселяймо!
- Ой, венгерко, венгерко, венгерко,
Позич мені люстерко, люстерко:
Я си вуса підкручу, підкручу,          |
Завтра вранці доручу, доручу.          | (2)

Заспіваймо пісню веселеньку,
Про жіночку молоденьку,
Про жіночку заспіваймо,
Серце наше звеселяймо!
Маю жінку молоду, молоду,
Не пущу ї по воду, по воду:
Могла би ся втопити, втопити,          |
Мусів бися женити, женити.             | (2)

Заспіваймо пісню веселеньку,
Про мандрівця молоденького,
Про мандрівця заспіваймо,
Серце наше звеселяймо!
- Ой, дівчино, не вір ми, не вір ми,
Бо я хлопець мандрівний, мандрівний,
Я мандрую тут і там, тут і там,        |
Подобаюсь дівчатам, дівчатам.          | (2)','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_913686'), datetime('now')),datetime('now'));
