INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9152888','Кленова алея','Музика: Олександр Білаш Слова: Степан Щипачев','uk','ukraine_1991',NULL,NULL,'Олександр Білаш. Романси для середнього голосу з фортепіано. К.: Мистецво. - 1966. - 50 с.',NULL,'Що листя падало, що ніч пройшла,
Не пожалкую;
Буду пам''ятати, як нас тоді далеко
Завела алея кленів, світла і листата.

Обнялись ми в тіні осінніх віт,
І тіні кленів довшими ставали.
А місяць плив, спішив:
На цілий світ він був один на всіх,
Що покохали.

Що листя падало, що ніч пройшла,
Не пожалкую;
Буду пам''ятати, як нас тоді далеко
Завела алея кленів, світла і листата.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9152888'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9152888','Кленова алея','Що листя падало, що ніч пройшла,
Не пожалкую;
Буду пам''ятати, як нас тоді далеко
Завела алея кленів, світла і листата.

Обнялись ми в тіні осінніх віт,
