INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9155188','Апостоли добра','Слова: Вадим Крищенко. Виконує: Анатолій Паламаренко','uk','ukraine_1991',NULL,NULL,NULL,'До нинішньої "української влади" Виконує: Анатолій Паламаренко','Прийдіть апостоли добра
І сядьте у державні крісла.
Ганьба нова й ганьба стара
На нашій долі перевисла.

Усе не ті, усе чужі
Щосили пнуться у пророки,
Такі слизькі, як ті вужі,
Такі брехливі, як сороки.

Що їм держава та народ,
Не зрозуміли ласку Божу.
Ніяк набить не може рот,
Ніяк накрастися не може.

Гендлюють, дурять, продають,
Торгують весело й охоче,
За усмішку сховавши лють,
За папірець сховавши очі.

Не те чекалося — не те!
Перевернулось перше й друге,
Усе достойне і святе
Узяв нечистий у прислуги.

Коли закінчеться це все?
Коли зітхнемо ми спокійно?
Прийдіть апостоли добра -
Пришли їх Боже на Вкраїну!','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9155188'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9155188','Апостоли добра','Прийдіть апостоли добра
І сядьте у державні крісла.
Ганьба нова й ганьба стара
