INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9149786','Ой, у кирниці на Йорданиці','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, у кирниці на Йорданиці.
Так рано!                             |
Так рано-раненько радуйся, земленько, |
Христос нам ся народив!               | (2)

