INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_915384','Мамина криниця','Музика: Юрій Констанкевич Слова: Людмила Кірик-Радомська. Виконує: Світозари','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Висохла криниця в мами біля хати
Звідки пили воду, як були малі
Дивиться на небо стара сива мати     |
Як летять у небі сірі журавлі        | (2)

Приспів:
Не журися рідна, прилечу до тебе
Джерело розчищу, вишню напою
Бо ніколи в світі забувать не треба  |
Мамину криницю в рідному краю        | (2)

Журавлиний клекіт лине над садами
Кучерявить вишні голуба вода
Коли діти вдома видається мамі       |
Що прийшли до неї молоді літа        | (2)

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''cat:romansy'', ''Пісні про любов до батьків'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_915384'), datetime('now')),datetime('now'));
