INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_91580','Воротар','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.','Опис гри: Дівчата зі співом "їдем-поїдем" підбігають до "воріт" і намагаються усі крізь них "проїхати". Хлопці пропустивши домовлену раніше кількість дівчат, намагаються зупинити дівочий гурт, зачиняючи "ворота" (опускаючи руки). Дівчата, які "проїхали" у "ворота", стають у пари з парубками, а ті, що залишились, повертаються на своє місце, і співають знов. Гра продовжується, доки перед "ворітьми" нікого не залишиться.','Дівчата стають в ряд перед хлопцями. Співають:
Воротар, воротар, воротарчику,
Отвори, отвори воротонька!
Хлопці взявшись за руки, підносять їх догори, утворюючи
"ворота", відповідають:
Нема пана вдома, поїхав до Львова,
Ключі купувати, замки замикати.
Дівчата:
Що ж ми то, що ж ми то за пан їде?
Що ж ми то, що ж ми то за дар везе?
Сивими волоньками,
З ярими пчолоньками.
Хлопці:
То ми того не беремо,
То ми за то, то ми за то дякуємо.
Дівчата:
А що ж ви, а що ж ви берете,
За що ви, за що ви дякуєте?
Хлопці:
Золотеє, золотеє горняточко —
Крайнєє, крайнєє дитяточко!
Дівчата:
А ми мости розіб’єм
І всі гроші заберем!
Їдем-поїдем!
Основна мелодія','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_91580'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_91580','Воротар','Дівчата стають в ряд перед хлопцями. Співають:
