INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9160080','Пісня для мами (дитяча)','Музика: Леся Соболевська Слова: Леся Соболевська. Виконує: Наталя Миглис','uk','ukraine_1991',NULL,NULL,'Авторська нотна збірка "Світ на долоні"',NULL,'1.
Я для мами пісню заспіваю,
Кращої від мами я не знаю,
Що дала дитинство мені,
Над колискою співала лагідні пісні.

Приспів:
Хай тебе у радощах день не обмине,
Мамочко ріднесенька, сонечко ясне.

2.
Ти мені дала цілющу силу.
Хочу, щоб за мене ти раділа,
Щоб моя щаслива весна
Радістю твоє серденько тішила щодня.

Приспів.

3.
Ти для мене найдорожча в світі,
Я твоїм промінчиком зігріта
І тобі за ласку таку
Вишиваю квіточками скатертиночку.

Приспів.

4.
Кращої за тебе я не знаю
І для тебе пісню цю співаю.
Хай слова почують мої
І тебе оберігають янголи твої.

Приспів. (2).','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9160080'), datetime('now')),datetime('now'));
