INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9159181','Якби мені рубель','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Якби мені рубель та качалка,
Якби мені жінка Наталка,
Я б її цілував, милував,
Ще б до печі куховарку найняв.

Якби мені ступа та жорна,
Якби мені жінка моторна,
Що б мені вечерю варила,
Щоб до мене гарно говорила.

Ой, купив я рубель та качалку,
Взяв я собі жінку Наталку.
Я ж її та й нагайко,
Щоб була мені хазяйкою','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9159181'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9159181','Якби мені рубель','Якби мені рубель та качалка,
Якби мені жінка Наталка,
Я б її цілував, милував,
Ще б до печі куховарку найняв.

Якби мені ступа та жорна,
Якби мені жінка моторна,
Що б мені вечерю варила,
Щоб до мене гарно говорила.

Ой, купив я рубель та качалку,
