INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9160889','Я козак з України','Музика: Олександр Кошиць Слова: народні. Виконує: Остап Кіндрачук','uk','ukraine_before_1917',NULL,NULL,'Остап Кіндрачук','Пісня була в репертуарі хору "Кошиця", створеного О.Кошицем. Записана в кубанських козаків.','Я козак з України,
Козак з роду, козак з міни, гей...
Гей, я козак з України,
Козак з роду, козак з міни.

Ніґде в життю не заплачу
Гукну, крикну, граю, скачу, гей...
Гей, не заплачу
Гукну, граю, скачу.

Отак у нас в Запорожжі —
Хоч нагайка плечі зріже
Козак на те не заплаче —
Гукне, крикне, грає, скаче, гей...
Гей, не заплаче —
Гукне, грає, скаче.

Жидам трясся, що ся бідять,
Що над грішми іно сидять.
Не з розкошів, тільки з біди
Тну гопака, йду в присіди, гей...
Гей, тільки з біди я йду в присіди.

Отак у нас чабарашки
То попід стіл, то все рачки,
То на пальцях, то в присіди,
То до корчми, то в сусіди, гей...
Гей, то в присіди я йду в сусіди.

Чого ж ти ся зажурила,
Дівчинонько моя мила,
Невелика серцю туга —
Не ти будеш, буде друга, гей...
Гей, серцю туга, не ти буде друга.

Я козак з України,
Козак з роду, козак з міни, гей...
Гей, я козак з України,
Козак з роду, козак з міни.','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9160889'), datetime('now')),datetime('now'));
