INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9164282','Хліб на рушнику','Музика: В. Філіпенко Слова: Вадим Крищенко','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003','"З репертуару багатьох хорових колективів"(цитата)','Стоять хліба достиглі серед поля,
А полем котить хвиля нешвидка.
В чеканні жнив завзятий день поволі
Схиляється чолом до колоска.

Приспів:
Золотим промінням
Світить щедрий сніп,
Найдорожче серцю
Добре слово "хліб".
Хліборобській долі
На її віку
Житнім сонцем сходить
Хліб на рушнику.

В безмежжі жнив земля озветься звуком,
Бо пісня й хліб поєднані давно.
Хвала, хвала вам, роботящі руки,
Які добром наповнили зерно.

Приспів.

З крутих доріг вертаєм в отчу хату,
Зорить вона віконцем до воріт,
Щоб мамин хліб святий поцілувати,
Що нас ростив, благословляв на світ.

Приспів.','[''pisni.org.ua'', ''cat:khlib'', ''Пісні про хліб'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9164282'), datetime('now')),datetime('now'));
