INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9152188','Крила','Музика: Юлія Голумбовська Слова: Ліна Костенко','uk','ukraine_1991',NULL,NULL,NULL,'сімейне тріо Колганових.(Ольга,Ірина,Маргарита)','А й правда, крилатим ґрунту не треба.
Землі немає, то буде небо.
Немає поля, то буде воля.
Немає пари, то будуть хмари.
В цьому, напевно, правда пташина...
А як же людина? А що ж людина?

Приспів:
Живе на землі. Сама не літає.
А крила має. А крила має!

Вони, ті крила, не з пуху-пір"я,
А з правди, чесноти і довір"я.
У кого - з вірності у коханні.
У кого - з вічного поривання.
У кого - з щирості до роботи.
У кого - з щедрості на турботи.
У кого - з пісні, або з надії,
Або з поезії, або з мрії.

Людина нібито не літає...
А крила має. А крила має!','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9152188'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9152188','Крила','А й правда, крилатим ґрунту не треба.
Землі немає, то буде небо.
Немає поля, то буде воля.
Немає пари, то будуть хмари.
В цьому, напевно, правда пташина...
А як же людина? А що ж людина?

Приспів:
Живе на землі. Сама не літає.
А крила має. А крила має!

Вони, ті крила, не з пуху-пір"я,
А з правди, чесноти і довір"я.
У кого - з вірності у коханні.
У кого - з вічного поривання.
У кого - з щирості до роботи.
У кого - з щедрості на турботи.
У кого - з пісні, або з надії,
Або з поезії, або з мрії.

Людина нібито не літає...
А крила має. А крила має!');
