INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_916281','Ой як то ще було із Нащада Світа','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Ой як то ще було із Нащада Світа — Колядка стародавня: Українське Різдво Світа. Тогди не було Неба ні Землі. Ой но на Морі Павутиноньки. РОЗСПІВ: Ой- як- то- ще- бу-ло- із- На-ща-да- Сві-та- Ра-дуй-тесь- Ой- ра-дуй-тесь- Лю-де- що- вже- Світ- на-ро-див-ся- Колядки й Щедрівки є висловом реліґійних ідей, які в довговіковому культурно-історичному розвитку народу назбиралися й уложилися в культурні верстви. Святочні обряди були би для сучасного Українського народу пустою формою, колиб не виповнювали їх ідейним змістом Колядки і Щедрівки. Тому будуть вони розсліджувані в зв''язку з дальшою темою культурно-історичної постаті Староукраїнських свят. Наперед будуть обговорені Світотворчі Колядки, відтак Колядки іншого культово-реліґійного змісту; опісля буде розглянене свято Щедрого Вечера і Водорщів; а за цим будуть опрацьовані Щедрівки. Колядки і Щедрівки не будуть тут віддільно опрацьовані, хоч уся дальше дослідження буде по правді лише їх розслідом. Заложена з початку головна тема праці про свято Різдва і Щедрого Вечора може бути лише на підставі розсліду Колядок і Щедрівок вичерпана. Навіть можлива дальша тема про Гаїлку знаходить в них своє опертя, бо вони є висловом Староукраїнських традицій реліґійних, суспільних та господарських, на яких основуються свято Різдва і Щедрого Вечера, а з цими святами має Гаїлка ідейний зв''язок. Ідея Почину Світа і його Творця. Староукраїнські Колядки мають в першій мірі всі характер культово-реліґійний, з кількома відмінами реліґійного шанування відповідно до культурно-історичного розвитку Українського народу. Та основою цього шанування є ідея Почину Світа і його Творця. Для того всі Українські Колядки можна визначити як міти про Почин Світа і Первовічне людське життя. Тому то і традиції про первісне господарське й суспільне життя народу містяться в Колядках. Абстрагуючи ці останні та лишаючи на пізніше критичний розгляд культових мотивів, потрібно взяти передовсім за предмет досліду головний мотив Колядок — питання Почину Світа, упорядкувати схематично Колядки з світотворчою темою й розглянути їх критично. Навіть дальша тема про Гаїлку знаходить в них своє опертя, бо вони є висловом Староукраїнських традицій реліґійних, суспільних та господарських, на яких основуються Свято Різдва і Щедрого Вечера, а з цими Святами має Гаїлка ідейний зв''язок. Два роди світотворчих Колядок. Отож суть Колядки світотворчі двоякого роду: — одні співають виключно про подію Почину Світа, або про поодинокі світотворчі події Первовічної доби, — другі, між котрими є також багато Щедрівок, подають уривочні спомини про Першу світову добу. В цих останніх, звичайно в їх заспівах, поет-співець неначе лише покликується на первовічні мітичні події, або натякає на них (алюзії); але ці поклики й натяки приявляють цінний матеріял до питання Почину Світа в Українських традиціях та до порівняння їх з світовим фольклором на цю тему. Перших Колядок є мало; мабуть багато світотворчих Колядкових традицій уступило перед біблійною й християнською ідеольоґією. Других Колядок, а властиво цих мітичних світотворчих заспівів, є многота; вони входять і в Колядки з християнською ідеольоґією, як поетична їх окраса; а в дійсності є лучником старої ідеольоґії з новою. Традиції Спасителя і старинна ідея Бога. В старовіцьких Колядках про Почин Світа нема спомину про особистого Творця; у деяких бувають лиш приспіви (рефрени) з окликами до Бога і Сина Божого. — Не можна бути певним, що вони є пізнішими додатками з доби християнської. Вони якраз роблять вражіння висловлювань мітичного змісту про Сина Божого, хто''зна чи не в зв''язку з традиціями Полудня про Спасителя Світа; але все таки криється в них, хоч би й старинна, ідея про Бога. Значна частина Колядок, як побачимо опісля з Місячною символікою, має за тему ненастанну творчість "Господа", яка приявлюється у всевідживаючій природі. Вони подобають на реліґійні роздуми з приводу Сотворення Світа, бо вказують на залежність від "Господа" всього життя в природі. І вони по своїй суті — і змістом і формою — належать до Колядок про Почин Світа. Пракультурна реліґійна ідеольоґія: поклін Богу. Реліґійна їх ідеольоґія є дуже старинна, можна сказати — пракультурна, мимо того, що бувають вони попереплітані ідеями й іменами християнськими. А зовсім самостійний світогляд виявляють Колядки, присвячені саме питанню Почину Світа. Вони в цій темі не зв''язані ані християнськими, ані біблійними поглядами і очевидно складені народом дуже давно і в більшій частині самочинно та незалежно. Вони дають матеріял великої вартости для культурно-історичних етнольоґічних дослідів над Українським народом. В зв''язку з головною темою праці оця частина Колядок, з якими лучиться ідеольоґійно багато Щедрівок, утверджує в нас наново погляд, що провідною думкою Українського старовіцького свята Коляди була ідея Різдва, себто зродження Світа і поклін Творцеві. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Читати листки, де є згадка з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Первовічна Павутинка: Ой як то було з Початку Світа Стежки до інших листків про Українські традиції.','Ой як то ще було із Нащада Світа.
Приспів: Радуйтесь! Ой радуйтесь Люде
що вже Світ народився!

Ой як ще не було ні Землі ні Неба
А що тільки було та Синєє Море
А посеред Моря Зелений Явір
На Явороньку три Синії Птаxи
