INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9162683','Розмова з тобою','Музика: В''ячеслав Корепанов Слова: Вадим Крищенко. Виконує: Іво Бобул','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Мені вже певно так судилось -
Стрічатись й розлучатись знов,
Згорнувши руки, ніби крила,
До тебе знову я прийшов!
В розлуках наших та прощаннях
Я признаюсь, моя вина,
Та мовлю вперше і востаннє:
Для мого серця ти одна!

Приспів:
Я приходжу,
Я іду до тебе знову
На душевну, як на сповіді,
Розмову!
Я приходжу,
Щоб тобі ще раз сказати,
Що у цілім світі
Ти - найбільше свято!

Тобі доземно я вклонюся
За те, що довго ждеш мене
І власній долі посміхнуся,
Щоб забувалося сумне!
Біжить моя любов по сліду
І я, благаю, підожди,
Колись до тебе я приїду,
Щоб залишитись назавжди,
Назавжди!

Приспів. (2)','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9162683'), datetime('now')),datetime('now'));
