INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9168384','Ой ходить сон коло вікон **','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Ой ходить сон коло вікон,
А дрімота коло плота,
Питається сон дрімоти:
- Де ж ми будем ночувати?

- Де хатонька тепленькая,
Де дитинка маленькая,
Там ми будем ночувати,
Мале дитя присипляти.

Щоб виросло, не змарніло,
Щоб тяженько не хворіло,
Сили й розуму набралось,
Своїх батьків потішало.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9168384'), datetime('now')),datetime('now'));
