INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9168181','Спасибі вам, мамо!','Музика: Володимир Конощенко Слова: Дмитро Луценко. Виконує: Дмитро Гнатюк, Григорій Гаркуша','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Я часто ночами пригадую знов
Дитинства сполохану казку
Спасибі вам мамо, спасибі вам мамо,
Спасибі вам мамо за вічну любов
За вічну любов, і щедру, незміряну ласку,
І щедру, незміряну ласку!

Схилялось над ліжком привітне чоло,
Дрімали натомлені очі,
Спасибі вам мамо, спасибі вам мамо,
Спасибі вам мамо за ваше тепло
З ваше тепло, і довгі недоспані ночі,
І довгі недоспані ночі!

Дитинства не жду я із вирію знов,
Не вернеш і мамину казку,
Спасибі вам мамо, спасибі вам мамо,
Спасибі вам мамо за вічну любов
За вічну любов, і всю неоплачену ласку,
І всю неоплачену ласку!','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9168181'), datetime('now')),datetime('now'));
