INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9163580','Синові в дорогу','Музика: Віталій Філіпенко Слова: Микола Сингаївський. Виконує: Віктор Пашник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Синові в дорогу
Мати промовляла
Пісню свого серця
Зберегти.

Приспів:
Доле, моя доле,    |
А життя - не поле, |
Бо життя прожить - |
Не поле перейти.   | (2)

Може, у дорозі
Десь обпалять грози,
Ти до дому птахом
Прилети!

Приспів.

Пронеси ж, мій сину,
Пісню-Україну
І дорогу людям
Освіти!

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9163580'), datetime('now')),datetime('now'));
