INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9163281','Де ж ти, Хмелю?','Музика: Остап Кіндрачук Слова: Борис Олійник. Виконує: Остап Кіндрачук','uk','ukraine_1991',NULL,NULL,'Остап Кіндрачук','Вірш Бориса Олійника "Де ж ти, Хмелю?" написаний до Помаранчевої революції і передає тривогу українців за майбутнє і надію на захист Гетьмана!','Хмара грізно суне на Бориспіль.
Темна тиша опада в лиман...
Де ж ти, Хмелю, де ж ти забарився,— |
Богом нам дарований Богдан?         | (2)

Чи забрів по славі до зовиці,
Чи забравсь по старості на піч, —   |
Де б не був ти, Хмелю, озовися,     | (2)
Доки нам не одібрало річ.

Обступає душі наші грішні
Кредиторів нещадимий клан...
Хто, Богдане, володіє грішми,       |
Той тепер в Україні гетьман.        | (2)

Повертайся Хмелю доки світа
Бо чомусь не йде із голови,
Щось немовби про варшавське сміття, |
Щось як начебто про грязь Москви.   | (2)

Бо вже наша старшина вельможна,
Честь і вклади збувши за кордон,
Натякає здалеку: "А, може,          |
Так воно й судилось іспокон?"       | (2)

Потойсвітнім страхолісся дише
Сиза туча з неба до низин...
Повертайся, гетьмане, скоріше,      |
Поки грім наш дух не поразив!       | (2)

Облягає Київ різнолиця
Саранча із чотирьох сторін.
Як здамо, Зеновію, столицю, —       |
Хто замовить поминальний дзвін?     | (2)

Будем знову скиглити й стогнати,
Сипати на лисину золи,
Що, мовляв, трикляті супостати      |
Знов нас у ярма запрягли.           | (2)

Хмара встала з висі до пониззя,
Темна тиша впала на лиман.
Де ж ти, Хмелю, в трясці забарився,—|
Богом нам дарований Богдан?!        | (2)','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9163281'), datetime('now')),datetime('now'));
