INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9170487','Ісусе милий','Музика: о. Володимир Стех Слова: о. Володимир Стех','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Ісусе милий, Тебе ми просим,
В наших потребах, в нашій біді:
Помилуй грішних, спаси негідних,
Будем навіки вдячні Тобі!
Будем навіки вдячні Тобі!

Подай нам дари для духа, тіла,
Віру, надію в серцях скріпи,
Даруй побіду в борбах, спокусах,
Горе, терпіння осолоди!
Горе, терпіння осолоди!

Прости нам грішним гріхи, провини,
Нашої злоби не пом''яни,
Верни нам світлу одежу ласки,
В ласці умерти допоможи!
В ласці умерти допоможи!

Прийми, ісусе, молитву нашу,
З трону Твойого ласку зішли,
Любове наша, потіхо наша,
Всіх нас помилуй, всіх пом''яни!
Всіх нас помилуй, всіх пом''яни!    комп''ютерне відтворення (128 kbps)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christ'', ''Церковні пісні'', ''Пісні до Ісуса Христа'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9170487'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9170487','Ісусе милий','Ісусе милий, Тебе ми просим,
В наших потребах, в нашій біді:
Помилуй грішних, спаси негідних,
Будем навіки вдячні Тобі!
Будем навіки вдячні Тобі!

Подай нам дари для духа, тіла,
Віру, надію в серцях скріпи,
Даруй побіду в борбах, спокусах,
Горе, терпіння осолоди!
Горе, терпіння осолоди!

Прости нам грішним гріхи, провини,
Нашої злоби не пом''яни,
Верни нам світлу одежу ласки,
В ласці умерти допоможи!
В ласці умерти допоможи!

Прийми, ісусе, молитву нашу,
З трону Твойого ласку зішли,
Любове наша, потіхо наша,
Всіх нас помилуй, всіх пом''яни!
Всіх нас помилуй, всіх пом''яни!    комп''ютерне відтворення (128 kbps)');
