INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9169989','Романс для Степана Бандери','(Степане-Степане, за що тебе вбито?). Музика: Василь Дунець Слова: Степан Галябарда. Виконує: Василь Дунець','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Виростають сини на піснях, на казках, на молитвах
І ідуть по житті, як по кризі крихкій навесні.
Як їм нині і нам твою правду від лжі відділити?
Як твої зрозуміти, Степане, і ночі, і дні?

Приспів:
Степане-Степане, за що тебе вбито?
У чому твоя перед світом вина?
Твоя в тім провина, що є Україна, |
Твоя в тім вина, що любов є одна! | (2)

Ти у серці беріг віру в батька і в мамине слово,
І простити не міг тим, хто в душу заліз чобітьми,
Ти плекав на чужині стражденну зернину любові,
А на рідній землі висівали полову сини.

Приспів.

Час так стрімко пливе і загоюють рани руїни,
І до храму твого нині, рідний, відкрито ідем.
Хто життя своє склав за величність і честь України,
Хай не прощений нині та завтра прощений буде!

Приспів','[''pisni.org.ua'', ''cat:istorychni'', ''cat:romansy'', ''Історичні пісні'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9169989'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9169989','Романс для Степана Бандери','Виростають сини на піснях, на казках, на молитвах
І ідуть по житті, як по кризі крихкій навесні.
Як їм нині і нам твою правду від лжі відділити?
Як твої зрозуміти, Степане, і ночі, і дні?

Приспів:
