INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9171085','Господь вознесеся','Слова: о. І. К.','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Господь вознесеся в вічній славі нині,
Вже Го покривають кКрасні неба сині.
Приспів:
Величаймо, прославляймо,
Прославляймо, величаймо
Вознесення, вознесення
Спаса Христа!
О, горо святая, хто ж не рад тя знати?
Того, що вознісся, вічно прославляти.
Приспів.
В коло Єлеона нині ся збираймо,
Вознесення Спаса в піснях прославляймо!
Приспів.
Як же ж не славити Спаса вознесення?
В нім бо довершилось наших душ спасення.
Приспів.
З апостольським хором Спаса прославляймо,
З ангелами слави пісні заспіваймо!
Приспів.
Спасе, через ласку вознесення Твого
Низпішли нам в поміч Духа Пресвятого.
Приспів.
Щоб Святим ми Духом в вірі утвердились,
Після віри жили, неба дослужились!
Приспів.
В небі зі святими, щоб Тя оглядали
І з Отцем і Духом вічно прославляли.
Приспів.','[''pisni.org.ua'', ''cat:voskresni'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9171085'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9171085','Господь вознесеся','Господь вознесеся в вічній славі нині,
