INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9171384','Благовіщення','Музика: А. Гнатишин Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'З неба божий Гавриїл
Бачить сяйво міст і сіл,
Та знаходить Назарет -
Благовісний в нього лет.

Приспів:
О, радуйся, Дівице,
О, радуйся, Царице,
Богом вибрана.

Став неждано на поріг,
Поклонився їй до ніг:
Благодатна Ти в женах,
День новий в Твоїх руках.

Приспів.

Божа сила є без меж:
Спаса в лоні Ти зачнеш.
Дух пройме Тебе Святий,
Син врятує світ лихий.

Приспів.

Згодна Я — хай буде так,
Голос твій — любові знак!
Знаю, жде Мене журба,
Та Господня Я раба.

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:do-bohorodyci'', ''Церковні пісні'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9171384'), datetime('now')),datetime('now'));
