INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_91686','Пташка','(А ми пташку споймили). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.',NULL,'Вибирають поміж себе пташку, яка стоїть у колі.
Усі інші загадують когось з кола
(так, щоб пташка не знала) і, співаючи, водять хоровод.

А ми пташку споймили, споймили,
Кругом неї ступили, ступили.
"Скажи, пташко, скажи, прошу,
Яке ім’я, ім’я ношу?"

"Пташка" відгадує ім’я того, кого загадали,
як не відгадає то всі співають:

Не вгадала, не вгадала,
Як та пташечка ся звала!   (2)

Знову співають. Якщо пташка назвала правильне
ім’я, то співають

Угадала і сказала,
Як та пташечка ся звала!   (2)

Тоді “пташкою” стає інша дитина, гра продовжується.    Основна мелодія','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_91686'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_91686','Пташка','Вибирають поміж себе пташку, яка стоїть у колі.
