INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9167888','Зимова колискова','Музика: Наталя Гуркіна Слова: Наталя Гуркіна','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'Люлі-люлі, сонечко, засинай,
Ніч вкриває зорями небокрай,
А небесні янголи сиплять сніг,
Ляже гарним килимом біля ніг...

Люлі-люлі, сонечко, добрих снів!
Не топи проміннячком вдень снігів,
Хай малюють іскрами ковзани,
Завірюх з морозами не жени!..

Люлі-люлі, сонечко, не крутись,
Сни про тепле літечко додивись...
Хай же білі янголи сніг сніжать,
Будуть діток саночки з гір катать...','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9167888'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9167888','Зимова колискова','Люлі-люлі, сонечко, засинай,
