INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9172686','Святителю Миколаю','Слова: о. М. Л.','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Святителю Миколаю,
Помагай в потребі,
Покровителю святіший       |
На землі і в небі.         | (2)

Ти славний є в чудах многих
По нашій країні.
Тебе славим, прославляєм   |
Торжественно нині.         | (2)

Будь помічником ласкавим,
Святий чудотворче.
Хорони нас від всяких бід, |
Ласкавіший отче!           | (2)

До тебе ми все покірно,
Щиро прибігаєм.
В тобі помочі, потіхи      |
І ласки шукаєм.            | (2)

Вислухай наші моління,
Отче Миколаю.
Які до тебе в надії        |
Завжди засилаєм.           | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:svyatyy-mykolay'', ''Церковні пісні'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9172686'), datetime('now')),datetime('now'));
