INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9172580','Архистратиже',NULL,'uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Архистратиже небесних сил,
Перед тобою пекло дрожить,
А в блеску твоїх сріблистих крил
Любовю наше серце горить.

Вогненним вістрям твого меча
Ти адську силу ввік поборов,
В безодні зчезла гріховна тьма
В вічній неволі гріха оков.

Архистратиже, під провід твій
За волю Божу готові йдем,
За волю Божу йдемо в бій
І наші серця в жертву несем.

Архистратиже, не страшить нас
Ворогів пекла чорная тьма,
Веди нас сміло у кожний час —
Ти нам побіда в бою одна!','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9172580'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9172580','Архистратиже','Архистратиже небесних сил,
Перед тобою пекло дрожить,
А в блеску твоїх сріблистих крил
Любовю наше серце горить.

Вогненним вістрям твого меча
Ти адську силу ввік поборов,
В безодні зчезла гріховна тьма
В вічній неволі гріха оков.

Архистратиже, під провід твій
За волю Божу готові йдем,
За волю Божу йдемо в бій
І наші серця в жертву несем.

Архистратиже, не страшить нас
Ворогів пекла чорная тьма,
Веди нас сміло у кожний час —
Ти нам побіда в бою одна!');
