INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9174384','Бити кота, бити','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986','Нецки - ночви','Бити кота, бити -
Не хоче робити.
Бити кота по лапках,
Най не скаче по лавках.
А мій кіт
Та взяв ціп,
Пішов молотити.
Намолотив гречки
Коробочку й нецки.
Лапками згортає,
Хвостиком змітає,
А вусами віє,
А писком збирає,
А вухами вчиняє.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9174384'), datetime('now')),datetime('now'));
