INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9170786','Помилуй нас, Боже','Слова: о. мітрат Р. Лужний','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Помилуй нас, Боже,
До Тебе взиваєм,
Милосердя Твого
Смиренно благаєм:
Господи, помилуй!
Господи, помилуй!
Господи, помилуй!
Помилуй нас, Боже!
Помилуй!

Відверни ласкаво
Твій гнів справедливий,
Милостивий, Боже,
Многотерпеливий!
Господи, помилуй!
Господи, помилуй!
Господи, помилуй!
Помилуй нас, Боже!
Помилуй!

Тебе ображали,
Закони топтали
І перед Тобою
В гріхах проживали:
Господи, помилуй!
Господи, помилуй!
Господи, помилуй!
Помилуй нас, Боже!
Помилуй!

Очисти нас, Боже,
З гріхів і провинів,
Визволи нас нині,
З ворожих кайданів:
Господи, помилуй!
Господи, помилуй!
Господи, помилуй!
Помилуй нас, Боже!
Помилуй!

Неспокійне серце,
Нещасне в тривозі,
Доки не спочине
У Тобі наш, Боже:
Господи, помилуй!
Господи, помилуй!
Господи, помилуй!
Помилуй нас, Боже!
Помилуй!','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:strasni'', ''Церковні пісні'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9170786'), datetime('now')),datetime('now'));
