INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9171787','Ой, русалонько','Музика: Ігор Білозір Слова: Богдан Стельмах','uk','ukraine_before_1917',NULL,NULL,'Стельмах Б. М. Світлиця пісень і спогадів.- Львів: Сполом, 2001.',NULL,'Під зеленою водою
На самому дні
Плинуть стадом-чередою
Срібні окуні.
То не окуні,
То не окуні,
То сумні
Наші дні...

Приспів:
"Ой, русалонько, русалонько,
Звав мене козак. -
Зроблю тобі колисалонько -
Кленовий байдак.
Будеш в ньому колисатися:
Люлі-люлі-лю...
Сама собі признаватися:
Козака люблю..."

А коли холодний місяць
Блисне на воді,
Жаль зі смутком перемісять
Діви молоді.
Діви молоді
Рушать по воді
В самоті,
В сумоті...

Приспів.

Спалахнуть далекі півні
Золотим вогнем,
І поблідне чорна північ
Перед білим днем.
Перед білим днем
Золотим вогнем
Ми зітхнем
І заснем...

Приспів.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9171787'), datetime('now')),datetime('now'));
