INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9173585','Прощальний вальс','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Закурличуть в синім небі
Сизокрилі журавлі -
То із школою своєю
Я прощаюсь на зорі.

Приспів:
Вихором вальсу зорі кружляють,
Довгі пророчать літа.
А у душі весна розцвітає,
Юність моя золота!

Відцвіли каштани білі,
Тихий вечір зажуривсь,
Ми з тобою так хотіли
Стать дорослими колись.

Приспів.

Забринить в душі тривога,
Відлітаєм у життя,
Вже чекають нас дороги,
Невідоме майбуття.

Приспів. (2)

Юність моя золота!','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9173585'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9173585','Прощальний вальс','Закурличуть в синім небі
