INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9165683','Хай живе надія','Музика: Ірина Білик Слова: Ірина Білик, Костянтин Гнатенко. Виконує: Ірина Білик','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мріє росточок явором стати,
Пташка маленька - в небі літати.
Вірить у диво кожна людина,
Вірить матуся в доньку і в сина!

Приспів:
Хай живе, хай живе надія!
Хай земля, хай земля радіє!
Хай печаль серце оминає
І добро всіх людей єднає!

Ночі вишневі в зоряній тиші,
Вітер блакитно жито колише.
Ми збережемо нашу єдину,
Рідну вкраїну, славну родину!

Приспів.

Хай живе, хай живе надія!
І добро всіх людей єднає!','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9165683'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9165683','Хай живе надія','Мріє росточок явором стати,
Пташка маленька - в небі літати.
Вірить у диво кожна людина,
Вірить матуся в доньку і в сина!

Приспів:
Хай живе, хай живе надія!
Хай земля, хай земля радіє!
Хай печаль серце оминає
І добро всіх людей єднає!

Ночі вишневі в зоряній тиші,
Вітер блакитно жито колише.
Ми збережемо нашу єдину,
Рідну вкраїну, славну родину!

Приспів.

Хай живе, хай живе надія!
І добро всіх людей єднає!');
