INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9175383','А під нашим окенечком','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.182','Виконує: Дівчата хору с.Боську','1. А під нашим оконечком лучка зелена,
Квитне на ній розмария, білий квиток ма.

Приспів:
Гей, гей, розмария, штом все тебе там виділа,
Кого я вірні любила, нич му не повіла.

2. Повідала твоя мама, же я худобна,
А мій милий таку глядат, што буде вірна.

Приспів.

3. Бодай би ви не мали ани ночи, ні дня,
Бодай ви були страплени, як то тепер я.

Приспів:
Гей, гей, розмария, штом все тебе там виділа,
Кого я вірні любила, нич му не повіла','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9175383'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9175383','А під нашим окенечком','1. А під нашим оконечком лучка зелена,
Квитне на ній розмария, білий квиток ма.

Приспів:
Гей, гей, розмария, штом все тебе там виділа,
Кого я вірні любила, нич му не повіла.

2. Повідала твоя мама, же я худобна,
А мій милий таку глядат, што буде вірна.

Приспів.

3. Бодай би ви не мали ани ночи, ні дня,
Бодай ви були страплени, як то тепер я.

Приспів:
Гей, гей, розмария, штом все тебе там виділа,
Кого я вірні любила, нич му не повіла');
