INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_917585','Із янголом на плечі','Музика: Плач Єремії, М. Бурмака Слова: Іван Малкович','uk','ukraine_1991',NULL,NULL,'http://www.ji.lviv.ua/ji-library/pleroma/malkovych.htm',NULL,'Краєм світу, уночі,
При Господній при свічі
Хтось бреде собі самотньо
Із янголом на плечі.

Йде в ніде, в невороття,
Йде лелійно, як дитя,
І жене його у спину
Сірий маятник життя, -

Щоб не вештав уночі
При Господній при свічі,
Щоб по світі не тинявся
Із янголом на плечі.

Віє вітер вировий,
Виє Ірод моровий,
Маятник все дужче буха,
Стогне янгол ледь живий...

А він йде і йде, хоча
Вже й не дихає свіча,
Лиш вуста дрижать гарячі:
"Янголе, не впадь з плеча."','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_917585'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_917585','Із янголом на плечі','Краєм світу, уночі,
При Господній при свічі
Хтось бреде собі самотньо
Із янголом на плечі.

Йде в ніде, в невороття,
Йде лелійно, як дитя,
І жене його у спину
Сірий маятник життя, -

Щоб не вештав уночі
При Господній при свічі,
Щоб по світі не тинявся
Із янголом на плечі.

Віє вітер вировий,
Виє Ірод моровий,
Маятник все дужче буха,
Стогне янгол ледь живий...

А він йде і йде, хоча
Вже й не дихає свіча,
Лиш вуста дрижать гарячі:
"Янголе, не впадь з плеча."');
