INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9173188','Подарунок','(Я так люблю цукерки). Музика: Алла Мігай. Виконує: Алла Мігай','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Що тобі подарувати,
Сонечко моє маленьке?
День, на радощі багатий,
Золотих веснянок жменьку?
Може, зграю слоненят?
Що тобі подарувать?
Що тобі подарувать?

Приспів: (2)
Я так люблю цукерки, ла-ла-ла-ла-ла-ла
Я так люблю торти, ла-ла-ла-ла-ла-ла
І всякі подарунки і всякі подарунки
Які даруєш ти ла-ла-ла-ла-ла-ла

Хочу я тобі сказати,
Що приємніш набагато,
Ніж одержувать дарунки,
Їх самому дарувати.
Тож давай не відкладать.
Що тобі подарувать?
Що тобі подарувать?

Приспів. (2)

Я так люблю цукерки, ла-ла-ла-ла-ла-ла
Я так люблю торти, ла-ла-ла-ла-ла-ла
І всякі подарунки, І всякі подарунки
Які даруєш ти
Та я тобі дарунок зроблю,
І не один.
Я слухатися буду, я слухатися буду
Ой, скільки?
...Аж цілих п''ять хвилин! ла-ла-ла-ла-ла-ла','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:zhartivlyvi'', ''Дитячі пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9173188'), datetime('now')),datetime('now'));
