INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9178580','Заробітчанка','Музика: Володимир Домшинський Слова: Вадим Крищенко. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,NULL,'Виконує: Павло Мрежук {267}','В жіночій долі смак гіркий,
Хоч залишилися вдома дітки.
Вкраїнські молоді жінки
Із дому йдуть на заробітки.
Далекий і нелегкий шлях,
Десь до Італії і далі
І в заклопотаних очах
Утіхи менше ніж печалі.

Приспів:
Як щастя мало, як щастя мало.
Згадаймо істину стару.
А під вікном чекають маму,
Чекають доню і сестру.
Як сліз багато, як сліз багато.
Чому це сталось — не збагнеш.
А без жінок пустіє хата, а без жінок пустіє хата.
І рідний край пустіє теж.

Нащо ті гроші — ви скажіть,
Коли розтоптуються душі,
Але людині треба жить
І каже жінка: "Їхать мушу",
І правда ця неначе ніж,
Який виблискує криваво -
Чого ж ти бачиш і мовчиш
Моя розгублена державо?','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9178580'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9178580','Заробітчанка','В жіночій долі смак гіркий,
Хоч залишилися вдома дітки.
Вкраїнські молоді жінки
Із дому йдуть на заробітки.
Далекий і нелегкий шлях,
Десь до Італії і далі
І в заклопотаних очах
Утіхи менше ніж печалі.

Приспів:
Як щастя мало, як щастя мало.
Згадаймо істину стару.
А під вікном чекають маму,
Чекають доню і сестру.
Як сліз багато, як сліз багато.
Чому це сталось — не збагнеш.
А без жінок пустіє хата, а без жінок пустіє хата.
І рідний край пустіє теж.

Нащо ті гроші — ви скажіть,
Коли розтоптуються душі,
Але людині треба жить
І каже жінка: "Їхать мушу",
І правда ця неначе ніж,
Який виблискує криваво -
Чого ж ти бачиш і мовчиш
Моя розгублена державо?');
