INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9175989','В темнім лісі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.241','Виконує: Магдалина Байко, с.Босько','1. В темнім лісі, в гаю зелененькім, (2)
Там пас коня козак молоденький.

2. А тим лісом дівчина ходила, (2)
В зеленому гаю заблудила.

3. Ти, козаче, козаче-гультяю, (2)
Вивед мене на дорогу з гаю.

4. Дав дівчині коника тримати, (2)
А сам пішов дороги шукати.

5. Шукав, шукав до темної ночі, (2)
Впала роса на темнії очі.

6. Сідай, дівча, на коника мого, (2)
Поїдемо до роду твойого','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9175989'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9175989','В темнім лісі','1. В темнім лісі, в гаю зелененькім, (2)
Там пас коня козак молоденький.

2. А тим лісом дівчина ходила, (2)
В зеленому гаю заблудила.

3. Ти, козаче, козаче-гультяю, (2)
Вивед мене на дорогу з гаю.

4. Дав дівчині коника тримати, (2)
А сам пішов дороги шукати.

5. Шукав, шукав до темної ночі, (2)
Впала роса на темнії очі.

6. Сідай, дівча, на коника мого, (2)
Поїдемо до роду твойого');
