INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9171484','До стіп Твоїх, Діво','Музика: О. Гуньовський Слова: О. Гуньовський','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'До стіп Твоїх, Діво Пречиста,
Схилилась вся краса мая,
Головки цвітів, зелень листя,     |
А з ними вся душа моя.            | (2)

З леготом вітру спів пташини
Крізь море світла йде до Тебе,
А з ним несеться ген до неба      |
Де Тебе, Мати, зойк дитини.       | (2)

Теплом любови збуди весну
У серцю скованім ледами.
Стопи леди, нехай слезами впадуть |
На душу і воскресну.              | (2)

І ласк росами зрости цвіти
Вірі, надії і любови,
Щоб ними душу пристроїти          |
Для Тебе в час весни обнови!      | (2)    комп''ютерне відтворення','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9171484'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9171484','До стіп Твоїх, Діво','До стіп Твоїх, Діво Пречиста,
