INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9172281','Пресвята Діво','Слова: о. В. Матюк','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Пресвята Діво, світла зорице,
Ми Тебе славим, наша Царице.
Приспів:
Ми Тя взиваєм і руки зносим, |
Спасай нас, спасай -         |
Усердно просим!              | (2)
Молись за нами, о наша Мати,
Не дай нам довше в гріхах зістати.
Приспів.
Ми лиш на тіло наше взирали,
За нашу душу не пам''ятали.
Приспів.
Ми в гріхах світу утіху мали,
О страшнім суді не пам''ятали.
Приспів.
Що ж тоді будем грішні робити,
Як Син Твій прийде всіх нас судити?
Приспів.
Він нас питати про це стане,
Чи ми так жили як християне?
Приспів.
Він нас спитає, що ми зділали
Для неба, Бога і Його слави.
Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:do-bohorodyci'', ''Церковні пісні'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9172281'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9172281','Пресвята Діво','Пресвята Діво, світла зорице,
