INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9179487','Святослав','Музика: Широкий Лан Слова: Широкий Лан. Виконує: Широкий Лан','uk','ukraine_1991',NULL,NULL,'vkontakte.ru/page27564751',NULL,'Здається, що пройшли часи великої держави
Яка колись давно гриміла на весь світ...
Тепер ми в себе вдома ні на що не маєм права
Хоч пережили ми разом немало тяжких бід.

Діти наші розкидані по світу неначе сироти
Хоча ми варті кращої долі
Тож станьмо же пліч-о-пліч мої слов''янські брати
Й підемо здобувати Батьківщині волю!!!

Приспів:
Святослав, повстань із мертвих, поглянь на ці руїни!!!
Святославе, підніми із колін Русь - Україну!!!
Поведи наше військо вперед, ми готові до бою!!!
Подай княже нам знак й ми підем за тобою!!!

Стань же на чолі, наш князю, першої колони,
Й нехай зорі вкажуть тобі шлях.
До подиху останнього не зійдемо з дороги
Якщо ти поведеш нас по бойових стежках.

У небі чорні хмари віщують битву рокову
Й на дереві тужливо ворон кряче...
Покинули домівки рідні воїни молоді
Лиш матір за сином гірко плаче.

Приспів.

У полі височіють чорнії могили
Свідки слави наших дідів
Прокинься Святославе, додай нам духу й сили
Поки меч Війни ще не зогнив

Приспів.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9179487'), datetime('now')),datetime('now'));
