INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9181889','Чоперок','Музика: Вперше Чую Слова: Григорій Вагапов. Виконує: Вперше Чую','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Моя мати казала мені: синок,
Літай в поночах низько і помаленьку.
Тому я склепав собі чоперок,
Точно знаю, тра слухать неньку.

Запасаюсь болтами і гайками,
Буду байкером, буду байкером!
З самогоном, травою і лайкою
Буду байкером, буду байкером!
Буду байкером!

Мій татусь казав мені: ми, синок,
Врешті землю прикрасимо квітами.
Ми ж, як прадіди, рулимо до зірок
На "Планеті", можливо, "Юпітері".

Запасайтесь болтами і гайками,
На Юпітері рулять байкери!
З самогоном, травою і лайкою
Рулять байкери, рулять байкери!

Моя бабця співала мені пісень,
Я їх досі пригадую веснами,
Щоб коли навіть в родині ти сам, як пень,
Обростаєш братами і сестрами!

Обростаю Петрами і Гальками,
Буду байкером, буду байкером!
Із самогоном, травою і лайкою
Буду байкером, буду байкером!

Моя мати казала мені, синок
Літай в поночах низько і помаленьку!','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9181889'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9181889','Чоперок','Моя мати казала мені: синок,
