INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9177384','Романс про дует','Музика: Геннадій Желуденко Слова: Євген Летюк. Виконує: Геннадій Желуденко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'О, як вони співали, як співали!..
І велелюдні замовкали зали,
І люди потім в захваті казали
О, як вони співали,
Як співали!
А їй уже було, мабуть, за сорок,
І, певно, їй було вже трошки сором
Зрадливих зморщок під її очима
Від літ, що їх носила за плечима.
І в нього лік рокам був теж не скромний,
Були і в нього посивілі скроні,
І довгих літ вершини і завали...
А як вони співали, як співали!
Вони співали й бачили минуле,
І ворушили горе незаснуле,
І радощі, яких було немало -
Усе, що не різнило, а єднало!
Вони пройшли життя болючі тракти,
Вони зазнали і надбань, і втрати,
Вело їх щастя, може, й лихо гнало,
Та все те не різнило, а єднало!..

І то не просто пісні рівні звуки,
То з''єднані навік надійні руки,
Що їх не всім поталанило мати,
Тому вони і вміли так співати...

О, як вони співали, як співали!..
І велелюдні замовкали зали,
І люди потім в захваті казали
О, як вони співали,
Як співали!','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9177384'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9177384','Романс про дует','О, як вони співали, як співали!..
І велелюдні замовкали зали,
І люди потім в захваті казали
О, як вони співали,
Як співали!
А їй уже було, мабуть, за сорок,
І, певно, їй було вже трошки сором
Зрадливих зморщок під її очима
Від літ, що їх носила за плечима.
І в нього лік рокам був теж не скромний,
Були і в нього посивілі скроні,
І довгих літ вершини і завали...
А як вони співали, як співали!
Вони співали й бачили минуле,
І ворушили горе незаснуле,
І радощі, яких було немало -
Усе, що не різнило, а єднало!
Вони пройшли життя болючі тракти,
Вони зазнали і надбань, і втрати,
Вело їх щастя, може, й лихо гнало,
Та все те не різнило, а єднало!..

І то не просто пісні рівні звуки,
То з''єднані навік надійні руки,
Що їх не всім поталанило мати,
Тому вони і вміли так співати...

О, як вони співали, як співали!..
І велелюдні замовкали зали,
І люди потім в захваті казали
О, як вони співали,
Як співали!');
