INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9181','Я піду в далекі гори','Музика: Володимир Івасюк Слова: Володимир Івасюк. Виконує: Квітка Цісик, Володимир Івасюк, Русичі, Марія Яремчук','uk','ukraine_before_1917',NULL,NULL,'http://ivasyuk.domivka.net/',NULL,'Я піду в далекі гори, на широкі полонини
І попрошу вітру зворів, аби він не спав до днини.
Щоб летів на вільних крилах на кичери і діброви
І дізнавсь, де моя мила - карі очі, чорні брови.
Приспів:
Мила моя, люба моя, світе ясен цвіт.
Я несу в очах для тебе весь блакитний світ.
Я несу любов-зажуру,   мрію молоду,
І сади цвітуть для мене,   як до тебе йду.
А як вітер з полонини полетіти не захоче,
Все одно знайду дівчину - чорні брови, карі очі.
Перейду я бистрі ріки, і бескиди, і діброви
І шляхи мені покажуть карі очі, чорні брови.
Приспів.
Програш (двічі): G C | D G H7 | Em Am | H7
Приспів.','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9181'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9181','Я піду в далекі гори','Я піду в далекі гори, на широкі полонини
І попрошу вітру зворів, аби він не спав до днини.
Щоб летів на вільних крилах на кичери і діброви
І дізнавсь, де моя мила - карі очі, чорні брови.
Приспів:
Мила моя, люба моя, світе ясен цвіт.
Я несу в очах для тебе весь блакитний світ.
Я несу любов-зажуру,   мрію молоду,
І сади цвітуть для мене,   як до тебе йду.
А як вітер з полонини полетіти не захоче,
Все одно знайду дівчину - чорні брови, карі очі.
Перейду я бистрі ріки, і бескиди, і діброви
І шляхи мені покажуть карі очі, чорні брови.
Приспів.
Програш (двічі): G C | D G H7 | Em Am | H7
Приспів.');
