INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9184080','Я жду тебе','(Осінній вечір...). Музика: І. Вовчак, Олексій Чухрай Слова: Дмитро Луценко','uk','ukraine_1991',NULL,NULL,'Д. Луценко "Усе любов''ю зміряне до дна", видавництво "Криниця", 2005',NULL,'Осінній вечір, тихий листопад,
Пішла ти й не вернулася назад...
Я обходив усі стежки планети,
Озвися, ненаглядна, де ти, де ти?
Я жду тебе, а роки, наче дим,
Пливуть, пливуть за обрій білих зим.

Мені здається, ніби угорі
Не зорі - а вогнисті янтарі...
Твоїх очей промінчики незгасні,
такі ласкаві, і такі прекрасні.
І я в журі привабливих ночей
Ловлю, ловлю тепло твоїх очей.

Мені здається, ніби у саду
Не яблуня, а ти стоїш в цвіту...
І в серці жар безгрішної любові
Палає, як весни рожева повінь.
І я несу той цвіт, немов фату,
Крізь будні літ і згубну мерзлоту.

А за порогом мокрий листопад,
І ти не повертаєшся назад...
Я обходив усі стежки планети,
Озвися ж, ради Бога, де ти, де ти?
Я жду тебе, а роки, наче дим,
Пливуть, пливуть за грані білих зим.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9184080'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9184080','Я жду тебе','Осінній вечір, тихий листопад,
