INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9176888','Оберіг пам''яті','Музика: Леонід Попернацький Слова: Володимир Матвієнко. Виконує: Оксана Голуб, Ольга Ларіна','uk','ukraine_1991',NULL,NULL,NULL,'аранжування - LEON KENNY','Весною в рідному краю
Я знов з травою розмовляю
І думку зважую свою,
Мов небо зоряного краю.

Приспів:
Тут хати отчої поріг,
Тепло родинної оселі,
І пам''ять, наче оберіг,
Тримає дні - сумні й веселі.

По краплі засвічу красу -
І стане ще світліше в світі.
Її ж, мов серце, пронесу
В однім довічнім заповіті.

Приспів:
Тут хати отчої поріг,
Тепло родинної оселі,
І пам''ять, наче оберіг,
Тримає дні - сумні й веселі','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9176888'), datetime('now')),datetime('now'));
