INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9185188','Ой, летів шуляк над вулицю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, летів шуляк
Над вулицю,
Вхопив Ганнусю
За спідницю.

Біжить Микола
Та й ґвалтує:
Ніхто Ганнусі
Не рятує!

Біжить Микола:
Гай-гай, гай-гай,
