INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9181281','Пісня про Волинь','Музика: Анатолій Пашкевич Слова: Дмитро Луценко. Виконує: Волинський народний хор','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ти у гаях, озерах и долинах,
Ти у розлогих вербах і калинах.
Ти вся в льонах, що грають як перлинки,
Ти рідна мати Лесі Українки.

Приспів:
Гойда, як море, Світязь хвилю синю,
Зовуся я красунею Волині.
Я вся в гаях, озерах і долинах,
Я вся в розлогих вербах і калинах.

Ти у хлібах, янтарних, мов жарптиця
Ти у стрімкому леті, як орлиця
Любов даруєш хлопцям і дівчатам
Бо ти щаслива й долею багата

Приспів.

Горжуся я і доньками й синами
Землею й мирним небом, що над нами
Де грає ніжним цвітом, як барвінки
Безсмертна слава Лесі Українки

Приспів','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9181281'), datetime('now')),datetime('now'));
