INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9185282','Перепілонько біла','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Перепілонько біла,
Де ж ти будеш сиділа?
Вже немає жита,        |
Вже нема пшениці       |
На господаревій нивці. | (2)

Перепілонько мала,
Де ся будеш ховала?
Вже немає жита,        |
Вже нема пшениці,      |
Бо кінець косовиці!    | (2)

Перепілонько-ненько,
Де ж ти будеш, серденько?
Та поїдьмо з нами      |
До нашої хати -        |
Будеш в нас зимувати!  | (2)','[''pisni.org.ua'', ''cat:halycki'', ''cat:obzhynkovi'', ''Пісні з Галичини'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9185282'), datetime('now')),datetime('now'));
