INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9190383','Мої казки','Музика: Леся Соболевська Слова: Наталія Руда. Виконує: Майя Негребецька','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ось книжечка маленька, в ній - схованка чудес.
Там виріс біб великий аж до самих небес.
Рій казочок веселий живе на сторінках.
Я скарб такий чудовий тримаю у руках.

Приспів:
Казки мої улюблені, улюблені казки.
Хоч їх напам''ять знаю, читаю залюбки.
Казки мої улюблені, улюблені казки.
Хоч їх напам''ять знаю, читаю залюбки.

Ось їде Попелюшка в кареті з гарбуза
І роги наставляє Коза їй Дереза.
Юнак Котигорошко врятує цілий світ,
Царівна-несміяна усіх нас розсмішить.

Приспів.

Ось море синє-синє, там - рибка золота
І біла скатертина чарівна, непроста.
Тікає від бабусі маленький Колобок.
Замовкли всі звірята - напевно, близько вовк.

Приспів','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9190383'), datetime('now')),datetime('now'));
