INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9189085','Хай щастить','Виконує: Берники','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Проминули роки непомітно
І коротке дитинство пройшло,
Безтурботне, щасливе і чисте, -
Не вернуть вам ніколи його.

Приспів:
Хай щастить вам в дорозі,  |
Щоб до неба вам дойти!     |
Не турбуйтесь, Бог поможе, |
Вашу долю освітить!        |
Хай для вас завжди лунає   |
Пісня щастя і добра!       |
Хай вас Бог благословляє   |
Від сьогодні до кінця!     | (2)

І тепер перед вами дорога
Повна щастя, розлук і біди.
Та не бійтесь, вам Бог допоможе
До кінця разом шлях свій пройти!

Приспів.

Хай кохання ніколи не згасне,
З кожним днем буде більше воно.
Вам бажаєм ми долі і щастя,
Ви від Бога чекайте його!

Приспів. (2)','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9189085'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9189085','Хай щастить','Проминули роки непомітно
І коротке дитинство пройшло,
Безтурботне, щасливе і чисте, -
Не вернуть вам ніколи його.

Приспів:
Хай щастить вам в дорозі,  |
Щоб до неба вам дойти!     |
Не турбуйтесь, Бог поможе, |
Вашу долю освітить!        |
Хай для вас завжди лунає   |
Пісня щастя і добра!       |
Хай вас Бог благословляє   |
Від сьогодні до кінця!     | (2)

І тепер перед вами дорога
Повна щастя, розлук і біди.
Та не бійтесь, вам Бог допоможе
До кінця разом шлях свій пройти!

Приспів.

Хай кохання ніколи не згасне,
З кожним днем буде більше воно.
Вам бажаєм ми долі і щастя,
Ви від Бога чекайте його!

Приспів. (2)');
