INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9183384','Жоржини','Музика: В. Гомоляка Слова: Дмитро Луценко. Виконує: Вадим Гомоляка','uk','ukraine_1991',NULL,NULL,'Д. Луценко "Усе любовю зміряно до дна", Київ, видавництво "Криниця", 2005',NULL,'Вдома посадила
Жоржини я,
Щоб десь не ходила
Любов моя.
Щоб десь не ходила
В чужім саду,
Душу не журила
Молоду.

Щедро поливала
Жоржини я,
Щоб крилоньки мала
Любов моя.
Щоб крилоньки мала,
Могла кохать,
Вечором літала
Розмовлять.

Вдова посадила
Жоржини я,
Певно, заблудила
Любов моя.
Певно, заблудила
Та й на біду.
Душу зажурила
Молоду','[''pisni.org.ua'', ''cat:films'', ''Українські пісні в кінофільмах'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9183384'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9183384','Жоржини','Вдома посадила
