INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9187889','Мамі','Музика: Олександр Пономарьов Слова: Олександр Пономарьов. Виконує: Олександр Пономарьов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли лишаєшся один на самоті,
Коли немає більше сил далі йти,
Ти знов прийдеш туди,
Ти знов прийдеш туди,
З її долонь напитись чистої води.
Ми заблукали
Поміж різних вулиць і країн,
Та за безмежними думками
Більш не стало слів,
Ти бачиш білі сни,
Радієш цій весні,
Та знову згадуєш її на самоті!

Приспів:
Повертаюсь, повертаюсь,
Я вдома, я вдома, я вдома,
Мама, мама, ма!
Я вдома, я вдома, я вдома,
Мама, мама, ма!
Я вдома, я вдома, я вдома,
Мама, мама, ма!
Я вдома, я вдома, я вдома,
Мама, мама, ма!
Я вдома, мамо!

Так іноді буває сумно в далині,
Так хочеться кричати сильно від німоти,
Ми пишемо листи від літа до весни,
Та тільки бачимо її вуста у сні.
А десь далеко стихне спека і підуть дощі,
І знову полетять лелеки до її душі,
Я знов прийду туди, ти знов прийдеш туди,
З її долонь напитись чистої води!

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9187889'), datetime('now')),datetime('now'));
