INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_919281','Пісня зачалась','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Вперше почув з емігрантських аудіозаписів у 70-х роках.','У 70-80 роки чув лише у виконанні емігрантів з аудіозаписів, тепер пісня реанімувалася й досить часто звучить на весіллях у виконанні музик, зокрема, під час знімання вельону і перегулювання.','Пісня зачалась, я дивлюся на тебе,
Ангелю, білим зіткана*...
Дай ми ручку, доню моя, потанцюємо разом       |
На твій весільний день.                        |

Але як скоро цей час проминає,
Рік за роком летить;
Ти була, маленька моя, може мала два рочки,    |
Я на руках носив.                              |(2)

Але ся крутять ті спомини про тебе,
Сльози в очах то веселі!..
Чи ти пам''ятаєш, доню, як на шпацір ми ходили  |
В неділю раненько?                             |(2)

З маленьких зерняток виросли два квіти, -
Нове життя починайте,
Жийте з Богом, діти мої, щастя я вам бажаю     |
На ваш весільний день!                         |(2)
*Варіант рядка:
Ангелю в білім зітканю...','[''pisni.org.ua'', ''cat:nostalgia'', ''cat:pro-batkiv'', ''cat:vesilni'', ''Пісні з ностальгічними мотивами'', ''Пісні про любов до батьків'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_919281'), datetime('now')),datetime('now'));
