INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9183982','Засвіт раненько',NULL,'uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно-літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.',NULL,'Засвіт раненько,
Засвіт раненько
Вставаймо,
І, замість мира,
Пісню заспіваймо
Владиці.
І побачимо Христа -
Сонце правди,
Що життя
Всім освітлює!

Засвіт раненько,
Засвіт раненько
Вставаймо,
І, замість мира,
Пісню заспіваймо
Владиці.
І побачимо Христа -
Сонце правди,
Що життя
Всім освітлює!','[''pisni.org.ua'', ''cat:voskresni'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9183982'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9183982','Засвіт раненько','Засвіт раненько,
