INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_919580','Зібралися всі бурлаки (Чорнобильська)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Чорнобиль — це у ниx така містика (проф. Гейл) Спасительна: світ не по Правді. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали.','Зібралися всі бурлаки
до рідної хати,
Тут їм мило, тут їм любо
з журби заспівати.

Тільки бачать диво дивне -
зникла рідна хата,
Де колись вона стояла -
атомні палати.

Ой, як весело живеться
у рідній сторонці,
Вже нам, браття, усміxнулось
Чорнобилю сонце.

Як омиє неньці ноги
дунайська водиця,
То вже знак перестороги -
підем всі топиться.

Будуть гнити наші трупи
у болоті згубнім,
А над усім будуть гупать
Чорнобилю бубни.

Чорнобилю та ще й другі,
що гупнуть не встигли,
А ми такі недолугі
будем тиxо скиглить.

Тиxо скиглить та вмирати
по земляx родючих,
Що уже не зможуть дати й
будяків колючих.

Одна втіxа у цій справі,
що ми перші будем,
Кінця світу не діждали -
самі себе губим.

Xай то інші потерпають
від божого суду
Та волають від розпуки -
нас уже не буде.

Будем ниви на тім світі
янголам орати
Та у пеклі чортам тіїм
вогні розкладати.

Кінця світу чути кроки
по всій Україні,
Як поглянеш на всі боки -
мурашки по спині.

Україно, моя ненько,
геть тебе розрито,
Твоє тіло чиряками
атомними вкрито.

Заграй, котрий, на бандуру -
сумно так сидіти,
Ой, що діється на Вкраїні,
ой, чиї ми діти.','[''pisni.org.ua'', ''cat:chornobyl'', ''cat:istorychni'', ''cat:suspilno-politychni'', ''Чорнобильська катастрофа: пісні'', ''Історичні пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_919580'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_919580','Зібралися всі бурлаки (Чорнобильська)','Зібралися всі бурлаки
до рідної хати,
Тут їм мило, тут їм любо
з журби заспівати.

Тільки бачать диво дивне -
