INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_918982','Дума про Карпатську Україну','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Записав 1988 р. від побратима по московському засланню родом з Коломийщини, з яким там здобували освіту.',NULL,'Послухайте, люди добрі,
Що маю казати, -
Я вам буду історичну
Співанку співати.

Поїхав я раз у поле
Сивими волами,
Двадцять років ми прожили
З польськими панами.

Пани польські добрі були,
Пили та гуляли,
А вни з наших українців
Всю шкіру здирали.

А вни пили та гуляли
Що день, що неділі,
Аж доки ся не довідав
Гітлер у Берліні.

Подивився Гітлер мапу
Де стоїт Європа, -
Ой то треба закликати
Пана Рібентропа.

Ой сів Гітлер з Рібентропом,
Стали говорити, -
А ми мусим у сім році
Чехію скреслити.

А як зачув це пан Бенеш,
Прийшов на нараду, -
А то треба українцям
Дати в руки владу.

А вкраїнці як схотіли,
То так і зробили, -
Десятого листопада
Уряд заложили.

Заложили вони уряд,
Заложили центра
Та й обрали Волошина -
Свого президента.

Став Волошин президентом,
Владу в руки бере,
Аж на це ся загнівала
Польща та Мадяри.

Мадяри ся загнівали,
Аж догори скачут,
А поляки у Варшаві
Мало що на плачут.

Плаче Польща та й говорит
Всякі небилиці -
Захотіла з Мадярами
Спільної границі.

Ой бо вони як схотіли,
То так і зробили -
Двайцятого вони грудня
Вкраїну розбили.

Пішов мадяр на Вкраїну,
Бо був дуже впертий,
Ой там наші січовики
Не могли їх сперти.

Ой бо тамки воювали
Одні добрі хлопці,
А як вони утікали,
То їх вбили копці.

Як зачув це пан Волошин,
Дуже зажурився,
Поїхав він до Гітлера,
З Гітлером сварився.

Не сварися, Волошине, -
Гітлер йому каже, -
Бо за твою Україну
Вся Польща поляже.

Ой сів Гітлер з Рібентропом,
Стали говорити, -
Ми мусимо у сім році
Клайпеду розбити.

А Клайпеду як розіб''єм -
Рік відпочиваєм,
А на другий у вересни
З Польщев починаєм.

Ой як стала Німеччина
Польщу розбивати,
Ой та стала з вороп''янів
Бомбами кидати.

Вкинула дві на Краків,
Одну на столицю,
А Речмігель із родинов
Утік за границю.

А Бик утік до Льондону,
Та й напився кави,
Але Гітлер забрав Краків,
Взявся й до Варшави.

Я співаю та й співаю,
Не сокиров тешу,
Ой скажіт ми, добрі люди,
Чи я вам що брешу.

Ой у мене перед хатов
Грушка посаджена,
А вже тота історична
Співанка скінчена.','[''pisni.org.ua'', ''cat:dumy'', ''cat:istorychni'', ''cat:suspilno-politychni'', ''cat:zakarpatski'', ''Думи'', ''Історичні пісні'', ''Суспільно-політичні пісні'', ''Закарпатські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_918982'), datetime('now')),datetime('now'));
