INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9199383','Канікули - Ура!','Музика: Ольга Янушкевич Слова: Марія Ясакова. Виконує: Мрія','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли учитись гірко і голова болить,
Не радує п''ятірка і двійка не страшить,
Напевно, то канікули спішать уже до нас:
Всі дивляться у вікна і не впізнати клас!

Канікули, канікули!
Радіє дітвора.
До нас ідуть канікули,
До нас ідуть канікули,
До нас ідуть канікули!
Канікули, ура!

Довкола все змінилось: притих гучний дзвінок
І крейда теж втомилась від наших помилок.
Чекають дива в школі дорослі і малі
Нам за ніч всім до волі, пробачте вчителі!

Канікули, канікули!
Радіє увесь клас!
Ми просим вас, канікули,
Ми просим вас, канікули,
Ми просим вас, канікули,
Щоб виручили нас!

Ганяє хтось футбола, хтось спить до десяти.
Відпочиває школа від гаму, суєти.
Завдання заховали в журнали на столі,
"Нарешті, дочекались!" - радіють вчителі!

Канікули, канікули!
Радіє дітвора.
До нас ідуть канікули,
До нас ідуть канікули,
До нас ідуть канікули!
Канікули, ура!
Канікули - Ура!','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:shkilni'', ''Дитячі пісні'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9199383'), datetime('now')),datetime('now'));
