INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_920282','Бабине літо','Музика: Анатолій Сердюк Слова: Віра Коваль','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Відійшло уже літечко босе.
Не повернеться знову назад,
І рудою лисичкою осінь
Непомітно прокралася в сад.
І розвісила скрізь павутинки,
Що горять проти сонця сріблом,
І, можливо, лише на хвилинку
Нас зігріла останнім теплом.

Приспів:
Бабине літо, бабине літо,
Бабине літо, як сон, поміж нас.
Ніжність остання рікою розлита,
Лине задумливий осені вальс.

Сяє неба блакитна хустинка,
В цей обман вірять ниви й гаї.
Нас зв''язала тонка павутинка,
Не порвтіь ненароком її.
Літо бабине казку шепоче,
Я послухаю - і обманусь,
Бо я вірю у сон цей охоче,
А прокинутись просто боюсь.

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_920282'), datetime('now')),datetime('now'));
