INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9199989','На Івана, на Купала','Музика: Тарас Питлик Слова: Тарас Питлик. Виконує: Гурт "Не сумуй"','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Кажуть, на Івана, кажуть, на Купала
Папороть опівночі цвіте.
Той, хто відшукає цвіт той казковий-
Щастя й кохання віднайде.
Ти не спи, кохана, у цю ніч чарівну,
Ти не бійся чарів, а піди,
Віднайди ту квітку папороті дивну,
Щоб були щасливі ми завжди.

Приспів:
Ой, не дрімай, чудо-цвіт той відшукай,
І не бійся ані чарів, ані тьми.
Ой, не засни, бо то цвіт той чарівний
Розцвітає у цю ніч лише на мить.

Кажуть, на Івана, кажуть, на Купала
Папороть опівночі цвіла.
Ти його проспала і не відшукала,
Щастя наше ти не зберегла.
Чом ти дуєш щічки знову на Марічку,
Що її тепер я покохав.
Бо вона не спала, цвіт той відшукала,
Що мене навік причарував.

Приспів','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9199989'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9199989','На Івана, на Купала','Кажуть, на Івана, кажуть, на Купала
