INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_919889','Три брати *',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Ой там у лузі при дорозі
Червоні ружі зацвіли
Ой там три браття з Прикарпаття
Життя за волю віддали.

Їх було троє, тільки троє
Мали гранати й шмайсери
Вони не знали, що друг зрадив
Катам червоної Москви.

Кати боївку обступили
Кричать: "Бандьори, руки ввєрх"
Хтось крикнув: "Слава Україні,
Ми не здамося, краще смерть".

І три брати поцілувались
Ніхто пощади не просив
І більш гранати там не рвались
І кулемет більш не строчив.','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_919889'), datetime('now')),datetime('now'));
