INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_920585','Козаче, козаче','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Записав наприкінці 1980-х на Львівщині.',NULL,'Козаче, козаче, я ж тобі не вірю, -
Зламаввись калину на моїм подвір''ю.

Зламаввись калину гілляву, гілляву,
Зрадиввись дівчину біляву, біляву.

Я її не зрадив, - сама ся зрадила,
Я коня виводив, - вона виходила.

Я коня виводив на росу, на росу,
Вона виходила на босу, на босу.

Я коня виводив зраненька, зраненька,
Вона виходила стихенька, стихенька.

Я коня виводив до бору, до бору,
Вона виходила з відерцем по воду.

Я коня виводив, коня вороного,
Вона виносила вина червоного.

А я вина не пив, під ноги коню лив,
Щоби-сь мила знала, що я тя не любив.

Щоби-сь мила знала, щоби-сь пам''ятала,
Щоби-сь козакові правди не казала.','[''pisni.org.ua'', ''cat:dances'', ''cat:halycki'', ''cat:waltzes'', ''Пісні до танцю'', ''Пісні з Галичини'', ''Вальси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_920585'), datetime('now')),datetime('now'));
