INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9207982','А літа','Музика: Володимир Будейчук Слова: невідомий. Виконує: Михайло Грицкан','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Здається ніби вчора
Зробила перший крок
І перше слово тихо
Ти сказала
І перший ще недавно
У тебе був урок,
І перша вчителька
Тебе навчала.
Моя маленька доня,
Так виросла вже ти,
За тебе моє серце
Знов радіє.
Хай буде світла доля,
Відкриються світи,
Та успіх твій в житті
Мене зігріє!

Приспів:
А літа, а літа
Так невпинно пливуть,
Мов хмаринки ті білі
По небу.
Є одна, є одна
У житті нашім суть -
Жити в Божій любові
Нам треба!

Тобі я, тату, вдячна
За все, що ти зробив,
За доброту твою
Та твою ласку.
Мене немов ту квітку
З любов''ю ти зростив,
Перетворив моє
Дитинство в казку!
Я буду пам''ятати
Ті літні вечори,
Прогулянки,
Дитячі каруселі.
Дитинство промайнуло
Та знову разом ми,
Ніколи не забуду
Дні веселі!

Приспів. (3)','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9207982'), datetime('now')),datetime('now'));
