INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9212786','Львівська школа 97','Музика: невідомий Слова: Людмила Терлецька. Виконує: Михайло Терлецький','uk','ukraine_1991',NULL,NULL,NULL,NULL,'При дорозі ялина й вербиця
В пишних шатах стоять день у день,
Подружились, неначе сестриці,
І запрошують в школу дітей.

Приспів:
Львівська школо дев''яносто сьома,
Світлих знань ти - святе джерело!
Рідна школо дев''яносто сьома,
Нам даруєш знання і тепло!

В нашу школу всі радо приходять,
Тут краса - аж душа завмира,
Мудрість в нас і знання поруч ходять,
Їх черпаєм, як воду з Дніпра.

Приспів.

Педагоги завжди поруч з нами,
Ми сягаєм мети залюбки,
Наш постійний контакт з вчителями -
Найщасливіші наші роки!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9212786'), datetime('now')),datetime('now'));
