INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_920786','Не дзвонила, не заходила','Музика: Мотор''ролла Слова: Мотор''ролла. Виконує: Мотор''ролла','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Комети, планети та краплі ртуті,
Плакати, солдати та що може бути.
Собі плескала на концертах,
Нервово дряпая зап''ястя,
Дешеві сльози у конвертах,
Забути де панує щастя.
Приспів:
Не дзвонила, не заходила,
Ніч тим часом все змінила.
Не любила, з розуму зводила
