INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9211889','Ой, Богдане, батьку Хмелю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, Богдане, батьку Хмелю,
Славний наш гетьмане!
Встала наша Україна
На вражого пана!
Гей, гей-гей-гей,
На вражого пана!

З Запорожжя, з Чигирина
Військо виступає,
Попереду грізний батько
Конем виграває!
Гей, гей-гей-гей,
Конем виграває!

Знає Корсунь і Пилява,
Знають Жовті Води,
Як водив своє козацтво
Богдан у походи!
Гей, гей-гей-гей,
Богдан у походи!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9211889'), datetime('now')),datetime('now'));
