INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9205080','Добрий день, матусю-Україно','Музика: Микола Ведмедеря Слова: Н. Рубальська','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Добрий день, матусю Україно!
Сходить сонце радості й добра.
Україно, я - твоя дитина,
Крапелька великого Дніпра.

Приспів:
Україно моя, золоті твої поля,
Небо ніжно-голубе,
Що під ним усе цвіте.
Яблуневі сади і смерекові ліси,
Ніжна пісня солов''я -
Рідна матінка Земля.

Не дивись, що я така маленька,
Час мине - я швидко підросту
І усю любов свого серденька
Я тобі в дарунок принесу.

Приспів. (2)','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9205080'), datetime('now')),datetime('now'));
