INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9207384','Геть, вороги, з України','Музика: Андрій Гнатишин Слова: Андрій Гнатишин','uk','ukraine_1991',NULL,'1992','1. Нас Україна зове (патріотичні пісні для школярів) / Упор. С. Стельмащук. – Львів: Світ дитини, 2009. – С. 78.','За джерелом 1: Геть, вороги, з України" вийшла друком в одному з дволисткових "пісенних метеликів" (так називали колись дво- чи однолисткові друковані видання невеликого формату) на початку 1940-х років в музичному видавництві Бориса Тищенка у Відні. Цей видавець (очевидно, емігрант з Наддніпрянщини) таких "метеликів" з українськими піснями випустив щонайменше сотню, а потім (1943) ще й окремий збірник "Рідна пісня". Були це переважно співанки народні і популярні авторські. Призначалися вони для виконання під супровід гітари або гармонії в опрацюванні українських композиторів, які проживали тоді в австрійській столиці. Ці "пісенні метелики" потрапили в той час і до мого рідного села Скородинці (на Тернопільщині), і я був одним із перших виконавців названого твору. Мелодію "Геть, вороги, з України" подаю у цьому збірнику так, як вона збереглася в моїй пам''яті. А слова, що вже були призабулися, допоміг відтворити варіант цієї пісні, записаний на Бережанщині (Тернопільска обл.) і надрукований у збірнику Василя Подуфалого "Повстанські пісні" (Тернопіль, 1992). Коли пісня була опублікована в одному з чисел "Світу Дитини", про неї відгукнулася відома в Австралії українська діячка і композитор Оксана Тарнавська. В листі до журналу вона пише: "... побачила в ч. 7-8/2008 пісню "Геть, вороги, з України" і зраділа. Цю пісню виконувала з моїм Молодечим Кафедральним хором у багатьох концертах у Мельбурні та інших місцевостях Австралії... Слова і музику написав молодий композитор Андрій Гнатишин, професор і диригент славного хору церкви св.Варвари у Відні". Сьогодні виконання анотованого твору можна адресувати тим антидержавним та протиукраїнським групам нечестивців (властиво ворогам), які ще, на жаль, безкарно діють в Україні.','Геть, вороги, з України!
Геть із широких степів!
Досить наруг і терпіння,
Досить кривавих катів!

Горді високі Карпати,
Наш дужий батько Дніпро
Кличуть до зброї ставати,
Кличуть скидати ярмо.

Наш чорнозем плодовитий,
Нашую славу батьків
Сміло будем боронити,
Сміло підемо у бій!

Станьмо всі враз, українці,
Станьмо, як сила одна,
І ворогів проженемо -
Свобода нам засія!','[''pisni.org.ua'', ''cat:43'', ''cat:istorychni'', ''cat:plastovi'', ''cat:povstanski'', ''cat:suspilno-politychni'', ''Еміґрантські пісні'', ''Історичні пісні'', ''Пластові пісні'', ''Повстанські пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9207384'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9207384','Геть, вороги, з України','Геть, вороги, з України!
