INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9201787','Тобі хочу співать алілуя',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Тобі хочу я співать "алілуя".
О, мій Господь, я Тобою живу.
За радість спасіння Tебе прославляю
І "алілуя" співаю!

Сила твоя - смерть влади немає,
Твоя любов - серце добрим стає,
Вічний мій Бог, я Тебе величаю,
І "алілуя" співаю!

Як прагну я Тобі бути вірним,
Всюди й завжди славить імя Твоє.
Чашу страждань з Христом поділяю
І "алілуя" співаю!','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9201787'), datetime('now')),datetime('now'));
