INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9201085','Моє щастя заховане в Бозі',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Моє щастя заховане в Бозі,
Не в земному житті чи ділах,
Бо кується воно в перемозі,
А все інше - це тління і прах.

Краю мій, я радію тобою
І всі мрії мої до тебе,
Там все радість святого спокою
І лиш віра туди приведе.

Моє серце завсіди радіє
І немає для нього границь
Бо з любов''ю Христовою діє
І п''є воду з джерельних криниць.

Вода чиста все прибуває,
Що з-під каменя завжди дзюрчить,
Вона рани мої омиває
І спокійно дає відпочить.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9201085'), datetime('now')),datetime('now'));
