INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9207484','Завтра в далеку дорогу *',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'1. Пісні УПА / Зібр. і ред. Лавришин З. – Торонто – Львів, 1996-1997. – С. 163.',NULL,'Завтра в далеку дорогу
Свого коня осідлаю,
Кріса закину на плечі,
Милу свою попрощаю.

Вихром полину я в поле,
Зелене море сколишу,
І незабудьку на спогад
Своїй дівчині я лишу.

Батькові, неньці вклонюся,
Рідних сестер попрощаю,
Шаблю припну я до боку,
Ворона свого замаю.

І виряджала матуся
Сина, ой, свого сокола,
Щастя для нього у бою
Щиро благала у Бога.

А дівчинонька соколу
Червону квітку подала,
Слава героям Вкраїни,
Вслід партизанам сказала.

Гей, там ідуть партизани,
Вітер за ними лиш віє,
І не одно серденятко
Тужить за ними та мліє.

І не один з партизанів
Більш не побачить родини,
І не пригорне дівчини -
Бо він у бою загине.

Ой та загине, загине,
Та не загине та слава -
Він, хоч упав, та розгромив
Тую ворожу навалу','[''pisni.org.ua'', ''cat:istorychni'', ''cat:povstanski'', ''Історичні пісні'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9207484'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_9207484','Завтра в далеку дорогу *','Завтра в далеку дорогу
Свого коня осідлаю,
Кріса закину на плечі,
Милу свою попрощаю.

Вихром полину я в поле,
Зелене море сколишу,
І незабудьку на спогад
Своїй дівчині я лишу.

Батькові, неньці вклонюся,
Рідних сестер попрощаю,
Шаблю припну я до боку,
Ворона свого замаю.

І виряджала матуся
Сина, ой, свого сокола,
Щастя для нього у бою
Щиро благала у Бога.

А дівчинонька соколу
Червону квітку подала,
Слава героям Вкраїни,
Вслід партизанам сказала.

Гей, там ідуть партизани,
Вітер за ними лиш віє,
І не одно серденятко
Тужить за ними та мліє.

І не один з партизанів
Більш не побачить родини,
І не пригорне дівчини -
Бо він у бою загине.

Ой та загине, загине,
Та не загине та слава -
Він, хоч упав, та розгромив
Тую ворожу навалу');
