INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9211686','Повертайся емігрантко','Музика: Олег Стаднік Слова: Олег Стаднік. Виконує: Надзбручани','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Скільки літ уже пройшло?..
За водою все спливло...
Тільки перша та любов
Не дає спокою знов!..
Як тебе я обіймав,
Як Хрещатик квітував...
То ж скажи, кохана, чом
Ти подалась за кордон?..

Приспів:
Емігрантко, емігрантко,
Ти - любов моя єдина,
Повертайся, емігрантко,
Разом жити в Україні!..
Звідси родом наша доля,
Тут гніздечко щастя звите.
Повертайся, емігрантко,
Докохати, долюбити!..

Як живеш, моя мадам,
Чи падіння, а чи злет?..
Може ти в пошані там?..
Я ж - джерел своїх поет!
Мчить експрес блакитний в світ
До півстанку доброти.
Може з круговерті літ
Ним приїдеш скоро ти!

Приспів.','[''pisni.org.ua'', ''cat:43'', ''cat:emigration'', ''Еміґрантські пісні'', ''Пісні про еміґрацію'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9211686'), datetime('now')),datetime('now'));
