INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_9215188','Коли ми були малі...','Музика: Євген Заставний Слова: Т. Василько','uk','ukraine_1991',NULL,NULL,'Авторське подання: Т. Василько, Є. Заставний. Танцює дощ. Львів: Ліга-Прес, 2008. - 56 с.',NULL,'Коли ми були малі,
Нас любили вчителі,
А, як ми повиростали,
Лобуряками прозвали.

Приспів:
Подивіться ви на нас:
Ми такі великі - клас!
Ми такі великі - клас!
Ми умієм танцювати:
Гоп, гоп, гоп!
Не кажіть нам тільки "Стоп!"
Гоп, гоп, гоп!
Гоп, гоп, гоп!
Не кажіть нам тільки "Стоп!"

Щоб не відали батьки,
Ми відшукуєм книжки:
В голові від них полова
І жахлива в нас вимова.

Приспів.

Пропадають марно дні -
Усі предмети нудні,
А відбути щоб уроки,
Жуйку цямкаєм у роті.

Приспів.

Біографія сумна:
Математика щодня
Та контрольна ще робота -
Нам женитися ж охота!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_9215188'), datetime('now')),datetime('now'));
